  v_events  jsonb := $jsonpayload$[{"d":"2025-01-05","a":"NEXT - 05.01.2025.pdf","l":76,"pi":20,"pm":15,"o":"Dia 1 do curso. Coluna ASSINATURA. Anotação rodapé: 34 presentes (32 presencial + 2 online), 39 faltas, 9 não inscritos. OBS sobre inscritos do dia 04 que precisavam ser incluídos."},{"d":"2025-01-19","a":"NEXT - 19.01.2025.pdf","l":79,"pi":14,"pm":20,"o":"Cabeçalho 'Dia 3'. Coluna era 'ASSINATURA' (não 'Presença'). Anotação no rodapé: 31 presentes + 1 online; 32 total; 15 não inscritos."},{"d":"2025-02-26","a":"NEXT - 26.02.2025.pdf","l":81,"pi":15,"pm":22,"o":"Dia 4. Coluna ASSINATURA. Anotação rodapé: 35 presentes online, 17 não inscritos. Vários manuscritos marcados como NÃO (não inscritos) à esquerda."},{"d":"2025-03-02","a":"NEXT - 02.03.2025.pdf","l":56,"pi":8,"pm":10,"o":null},{"d":"2025-03-09","a":"NEXT - 09.03.2025.pdf","l":74,"pi":17,"pm":8,"o":"Lista impressa nova (cohort B expandida com novos nomes). 3 páginas: pg1 e pg3 são lista, pg2 tem só anotações manuscritas (família Beloni)."},{"d":"2025-03-16","a":"NEXT - 16.03.2025.pdf","l":85,"pi":30,"pm":8,"o":"Anotação manuscrita no rodapé da pág 1: '32 presentes / 10 não estavam na lista. Dia 3 Next 16.03'"},{"d":"2025-03-23","a":"NEXT - 23.03.2025.pdf","l":87,"pi":14,"pm":12,"o":"Título do PDF corrigido manualmente para '23.03.2025' (em cima do '16/03/2025' impresso). Manuscritos com 'TEL NO WHATSAPP' como referência de telefone."},{"d":"2025-04-06","a":"NEXT - 06.04.2025.pdf","l":74,"pi":27,"pm":13,"o":"Adelia Croce e Everton Goncalves da Silva foram adicionados manuscritos no rodapé da pág 1. Roseane Silva Pereira tem anotação 'NÃO RECEBEU CONTATO GC'. Página 3 inteira é manuscrita - inclui anotação '+ ALPHA!!!' no topo."},{"d":"2025-04-13","a":"NEXT - 13.04.2025.pdf","l":78,"pi":19,"pm":12,"o":"Rafael Gripp tem telefone manuscrito '98410-1008' adicionado. Vários manuscritos no final."},{"d":"2025-04-27","a":"NEXT - 27.04.2025.pdf","l":74,"pi":18,"pm":6,"o":"Anotação manuscrita ao lado de Cecilia Ferrari: 'Amanda, Pamela, Wilma porém não assinaram'. Anotação ao lado de Mario de Azevedo mamed: '5 semana passada Nilton e não assinaram'. Anotação no rodapé p.3 ao lado de Raquel Fernandes: 'veio também dia 20/04 e não assinou'."},{"d":"2025-05-04","a":"NEXT - 04.05.2025.pdf","l":73,"pi":17,"pm":10,"o":"Rafael Gripp tem anotação manuscrita 'RAPHAEL' e telefone '21 98410 1008' e 'PRESENTE' escritos. Vitor Hugo Alves de Moraes aparece também repetido manuscrito."},{"d":"2025-05-18","a":"NEXT - 18.05.2025.pdf","l":90,"pi":21,"pm":6,"o":"PDF de 4 páginas. Página 4 inclui linhas manuscritas adicionais dentro do template da tabela. Manuscritos no rodapé da pág 3 (Kevyn, Daniela, Stuar) e mais 3 na pág 4."},{"d":"2025-05-25","a":"NEXT - 25.05.2025.pdf","l":97,"pi":17,"pm":8,"o":"PDF de 4 páginas. Anotação manuscrita no rodapé pág 1: 'Fernando Manhanini / Cléa Manhanini' com assinatura R(?). Manuscritos no início da pág 4 dentro da tabela."},{"d":"2025-06-01","a":"NEXT - 01.06.2025.pdf","l":78,"pi":12,"pm":5,"o":"Manuscritos no rodapé da pág 1: 'Daniela Campos / Ana Cristina Belga de Oliveira' com telefones '21.999242887' e '21.99124-3790' e ambos 'PRESENTE PRESENTE'."},{"d":"2025-06-08","a":"NEXT - 08.06.2025.pdf","l":87,"pi":16,"pm":9,"o":"9 manuscritos no final da pág 3, alguns fora da tabela (Gisele, Andreia, Andrea)."},{"d":"2025-06-15","a":"NEXT - 15.06.2025.pdf","l":90,"pi":13,"pm":8,"o":"Coluna Presença com assinaturas/marcas manuscritas. 8 nomes adicionais manuscritos no final."},{"d":"2025-06-22","a":"NEXT - 22.06.2025.pdf","l":102,"pi":21,"pm":3,"o":"Primeira linha 'Agatha Magalhaes Santos' está riscada (duplicada). Coluna Presença com escritas 'PRESENTE' e assinaturas. 3 nomes manuscritos no final. Observação 'CANCELADA EM JUL/25' ao lado de Debora Evelyn Martins da Costa."},{"d":"2025-07-06","a":"NEXT - 06.07.2025.pdf","l":67,"pi":24,"pm":11,"o":"Lista impressa termina em Thais Chagas. Vários nomes adicionais manuscritos no final."},{"d":"2025-07-13","a":"NEXT - 13.07.2025.pdf","l":51,"pi":21,"pm":7,"o":"Eliana Aparecida da Silva escreveu nome ao lado e PRESENTE. 7 nomes manuscritos no final."},{"d":"2025-07-20","a":"NEXT - 20.07.2025.pdf","l":57,"pi":21,"pm":6,"o":"Benício de Alvarenga Simões aparece como linha impressa (sem telefone) com assinatura. 6 nomes manuscritos no final (2 ao fim da pág 1 e 4 ao fim da pág 2)."},{"d":"2025-07-27","a":"NEXT - 27.07.2025.pdf","l":68,"pi":26,"pm":0,"o":"Lista totalmente impressa nas 3 páginas (sem manuscritos adicionais ao final). Marco Antonio Vitella Pires foi corrigido para 'Vitelli'."},{"d":"2025-08-03","a":"NEXT - 03.08.2025.pdf","l":46,"pi":11,"pm":7,"o":"Lista impressa menor (apenas alguns nomes selecionados). 7 nomes manuscritos no final."},{"d":"2025-08-10","a":"NEXT - 10.08.2025.pdf","l":38,"pi":19,"pm":3,"o":"5 nomes manuscritos no final."},{"d":"2025-08-17","a":"NEXT - 17.08.2025.pdf","l":49,"pi":15,"pm":7,"o":"2 manuscritos no rodapé pag 1 (Luiz Henrique Marins, Christiano M. Ramos) e 5 no rodapé pag 2."},{"d":"2025-09-07","a":"NEXT - 07.09.2025.pdf","l":22,"pi":6,"pm":3,"o":"Lista pequena (19 nomes impressos). 3 nomes manuscritos no final."},{"d":"2025-09-14","a":"NEXT - 14.09.2025.pdf","l":33,"pi":8,"pm":8,"o":"PDF de 1 página. Marcas de presença variam (assinatura, X, traço). Última linha do manuscrito (Marinho da C. Souza) parcialmente cortada na borda inferior."},{"d":"2025-09-21","a":"NEXT - 21.09.2025.pdf","l":43,"pi":11,"pm":8,"o":"PDF de 2 páginas. Algumas linhas do manuscrito têm anotações como 'Falhou no 3º módulo' e 'fechou pra aula' (riscado)."},{"d":"2025-10-05","a":"NEXT - 05.10.2025.pdf","l":27,"pi":3,"pm":9,"o":"PDF de 1 página."},{"d":"2025-10-12","a":"NEXT - 12.10.2025.pdf","l":30,"pi":14,"pm":0,"o":null},{"d":"2025-10-19","a":"NEXT - 19.10.2025.pdf","l":34,"pi":6,"pm":2,"o":"PDF de 2 páginas. Marcação 'PRESENTE' aparece em algumas linhas com assinatura na mesma célula."},{"d":"2025-10-26","a":"NEXT - 26.10.2025.pdf","l":35,"pi":8,"pm":3,"o":"PDF 