:"2026-04-05","i":768,"f":"impressa","p":false},{"d":"2026-04-05","i":188,"f":"impressa","p":false},{"d":"2026-04-05","i":6,"f":"impressa","p":true,"o":"marca: Ok"},{"d":"2026-04-05","i":357,"f":"impressa","p":false},{"d":"2026-04-05","i":199,"f":"impressa","p":false},{"d":"2026-04-05","i":371,"f":"impressa","p":true,"o":"marca: Ok"},{"d":"2026-04-05","i":611,"f":"impressa","p":false},{"d":"2026-04-05","i":630,"f":"impressa","p":false},{"d":"2026-04-05","i":434,"f":"impressa","p":true,"o":"marca: Ok"},{"d":"2026-04-05","i":650,"f":"impressa","p":false},{"d":"2026-04-05","i":659,"f":"impressa","p":false},{"d":"2026-04-05","i":674,"f":"impressa","p":false},{"d":"2026-04-05","i":677,"f":"impressa","p":false},{"d":"2026-04-05","i":680,"f":"impressa","p":false},{"d":"2026-04-05","i":470,"f":"impressa","p":true,"o":"marca: Ok"},{"d":"2026-04-05","i":471,"f":"impressa","p":true,"o":"marca: Ok"},{"d":"2026-04-05","i":479,"f":"impressa","p":false},{"d":"2026-04-05","i":321,"f":"impressa","p":true,"o":"marca: Ok"},{"d":"2026-04-05","i":342,"f":"impressa","p":true,"o":"marca: Ok"},{"d":"2026-04-05","i":296,"f":"impressa","p":true,"o":"marca: Ok"},{"d":"2026-04-05","i":776,"f":"impressa","p":false},{"d":"2026-04-19","i":513,"f":"impressa","p":false},{"d":"2026-04-19","i":532,"f":"impressa","p":false},{"d":"2026-04-19","i":541,"f":"impressa","p":false},{"d":"2026-04-19","i":561,"f":"impressa","p":false},{"d":"2026-04-19","i":173,"f":"impressa","p":true,"o":"marca: OK"},{"d":"2026-04-19","i":178,"f":"impressa","p":true,"o":"marca: OK"},{"d":"2026-04-19","i":580,"f":"impressa","p":false},{"d":"2026-04-19","i":188,"f":"impressa","p":true,"o":"marca: OK"},{"d":"2026-04-19","i":191,"f":"impressa","p":true,"o":"marca: OK"},{"d":"2026-04-19","i":195,"f":"impressa","p":true,"o":"marca: OK"},{"d":"2026-04-19","i":196,"f":"impressa","p":true,"o":"marca: OK"},{"d":"2026-04-19","i":599,"f":"impressa","p":false},{"d":"2026-04-19","i":644,"f":"impressa","p":false},{"d":"2026-04-19","i":215,"f":"impressa","p":true,"o":"marca: OK"},{"d":"2026-04-19","i":774,"f":"impressa","p":true,"o":"marca: OK"},{"d":"2026-04-19","i":223,"f":"impressa","p":true,"o":"marca: OK"},{"d":"2026-04-19","i":672,"f":"impressa","p":false},{"d":"2026-04-19","i":232,"f":"impressa","p":true,"o":"marca: OK"},{"d":"2026-04-19","i":238,"f":"impressa","p":true,"o":"marca: OK"},{"d":"2026-04-19","i":699,"f":"impressa","p":false},{"d":"2026-04-19","i":243,"f":"impressa","p":true,"o":"marca: OK"},{"d":"2026-04-19","i":250,"f":"impressa","p":true,"o":"marca: OK"},{"d":"2026-04-26","i":513,"f":"impressa","p":false},{"d":"2026-04-26","i":532,"f":"impressa","p":false},{"d":"2026-04-26","i":541,"f":"impressa","p":false},{"d":"2026-04-26","i":561,"f":"impressa","p":false},{"d":"2026-04-26","i":173,"f":"impressa","p":true,"o":"marca: X"},{"d":"2026-04-26","i":178,"f":"impressa","p":true,"o":"marca: X"},{"d":"2026-04-26","i":580,"f":"impressa","p":false},{"d":"2026-04-26","i":188,"f":"impressa","p":true,"o":"marca: X"},{"d":"2026-04-26","i":191,"f":"impressa","p":true,"o":"marca: X"},{"d":"2026-04-26","i":195,"f":"impressa","p":true,"o":"marca: X"},{"d":"2026-04-26","i":196,"f":"impressa","p":true,"o":"marca: X"},{"d":"2026-04-26","i":599,"f":"impressa","p":false},{"d":"2026-04-26","i":644,"f":"impressa","p":false},{"d":"2026-04-26","i":215,"f":"impressa","p":true,"o":"marca: X"},{"d":"2026-04-26","i":774,"f":"impressa","p":true,"o":"marca: X"},{"d":"2026-04-26","i":223,"f":"impressa","p":true,"o":"marca: X"},{"d":"2026-04-26","i":672,"f":"impressa","p":false},{"d":"2026-04-26","i":232,"f":"impressa","p":true,"o":"marca: X"},{"d":"2026-04-26","i":238,"f":"impressa","p":true,"o":"marca: X"},{"d":"2026-04-26","i":699,"f":"impressa","p":false},{"d":"2026-04-26","i":243,"f":"impressa","p":true,"o":"marca: X"},{"d":"2026-04-26","i":250,"f":"impressa","p":true,"o":"marca: X"},{"d":"2026-04-26","i":490,"f":"impressa","p":true,"o":"marca: X"},{"d":"2026-04-26","i":495,"f":"impressa","p":true,"o":"marca: X"},{"d":"2026-04-26","i":6,"f":"impressa","p":true,"o":"marca: X"}]$jsonpayload$::jsonb;
  v_default_igreja_id uuid := '00000000-0000-0000-0000-000000000001';
  v_count_eventos INT;
  v_count_membros_novos INT;
  v_count_inscricoes INT;
BEGIN
  -- ------------------------------------------------------------------
  -- 1) Tabelas temporarias com os dados crus
  -- ------------------------------------------------------------------
  CREATE TEMP TABLE _next_imp_persons (
    person_idx INT PRIMARY KEY,
    nome TEXT NOT NULL,
    telefone TEXT,
    telefone_norm TEXT,
    membro_id UUID
  ) ON COMMIT DROP;

  CREATE TEMP TABLE _next_imp_events (
    data DATE PRIMARY KEY,
    arquivo TEXT,
    total_lista INT,
    presentes_impressa INT,
    presentes_manuscritos INT,
    observacoes TEXT
  ) ON COMMIT DROP;

  CREATE TEMP TABLE _next_imp_records (
    data DATE NOT NULL,
    person_idx INT NOT NULL,
    fonte TEXT NOT NULL,
    presente BOOLEAN NOT NULL,
    observacao TEXT
  ) ON COMMIT DROP;

  -- ------------------------------------------------------------------
  -- 2) Carrega temp tables a partir dos JSON literais
  -- ------------------------------------------------------------------
  INSERT INTO _next_imp_persons (person_idx, nome, telefone, telefone_norm)
  SELECT
    (p->>'i')::int,
    p->>'n',
    NULLIF(p->>'t', ''),
    NULLIF(p->>'tn', '')
  FROM jsonb_array_elements(v_persons) p;

  INSERT INTO _next_imp_events (data, arquivo, total_lista, presentes_impressa, presentes_manuscritos, observacoes)
  SELECT
    (e->>'d')::date,
    e->>'a',
    (e->>'l')::int,
    (e->>'pi')::int,
    (e->>'pm')::int,
    NULLIF(e->>'o', '')
  FROM jsonb_array_elements(v_events) e;

  INSERT INTO _next_imp_records (data, person_idx, fonte, presente, observacao)
  SELECT
    (r->>'d')::date,
    (r->>'i')::int,
    r->>'f',
    (r->>'p')::boolean,
    NULLIF(r->>'o', '')
  FROM jsonb_array_elements(v_records) r;

  -- ------------------------------------------------------------------
  -- 3) UPSERT next_eventos (idempotente)
  -- ------------------------------------------------------------------
  INSERT INTO next_eventos (
    data, titulo, status, observacoes,
    total_lista, presentes_impressa, presentes_manuscritos, arquivo_origem
  )
  SELECT
    e.data,
    'NEXT - ' || to_char(e.data, 'DD/MM/YYYY'),
    'realizado',
    e.observacoes,
    e.total_lista,
    e.presentes_impressa,
    e.presentes_manuscritos,
    e.arquivo
  FROM _next_imp_events e
  ON CONFLICT (data) DO UPDATE SET
    status = 'realizado',
    total_lista = EXCLUDED.total_lista,
    presentes_impressa = EXCLUDED.presentes_impressa,
    presentes_manuscritos = EXCLUDED.presentes_manuscritos,
    arquivo_origem = COALESCE(next_eventos.arquivo_origem, EXCLUDED.arquivo_origem),
    observacoes = COALESCE(NULLIF(next_eventos.observacoes, ''), EXCLUDED.observacoes),
    titulo = COALESCE(NULLIF(next_eventos.titulo, ''), EXCLUDED.titulo),
    updated_at = now();

  GET DIAGNOSTICS v_count_eventos = ROW_COUNT;
  RAISE NOTICE 'next_eventos upserted: %', v_count_eventos;

  -- ------------------------------------------------------------------
  -- 4) Match contra mem_membros existentes por telefone normalizado
  --
  -- Regras (necessarias para idempotencia e para nao mesclar familia que
  -- compartilha telefone, ex: mae+filha):
  --   a) telefone normalizado precisa ter >=10 digitos e bater exato
  --   b) primeiro nome (sem acento, lower) precisa bater
  --   c) cada mem_membros so pode casar com 1 person_idx no batch
  --      (window function garante; se houver 2+ candidatos, vence o de
  --      menor person_idx)
  -- ------------------------------------------------------------------
  -- Helper inline para "unaccent" via translate (evita dependencia da
  -- extensao unaccent que pode nao estar habilitada).
  WITH candidates AS (
    SELECT
      p.person_idx,
      m.id AS membro_id,
      m.created_at,
      ROW_NUMBER() OVER (
        PARTITION BY m.id
        ORDER BY p.person_idx
      ) AS rn
    FROM _next_imp_persons p
    JOIN mem_membros m ON
      p.telefone_norm IS NOT NULL
      AND length(p.telefone_norm) >= 10
      AND regexp_replace(coalesce(m.telefone, ''), '\D', '', 'g') = p.telefone_norm
      AND lower(
        regexp_replace(
          translate(split_part(coalesce(m.nome, ''), ' ', 1),
            'áàâãäéèêëíìîïóòôõöúùûüçñÁÀÂÃÄÉÈÊËÍÌÎÏÓÒÔÕÖÚÙÛÜÇÑ',
            'aaaaaeeeeiiiiooooouuuucnAAAAAEEEEIIIIOOOOOUUUUCN'),
          '[^a-zA-Z0-9]', '', 'g'
        )
      ) = lower(
        regexp_replace(
          translate(split_part(coalesce(p.nome, ''), ' ', 1),
            'áàâãäéèêëíìîïóòôõöúùûüçñÁÀÂÃÄÉÈÊËÍÌÎÏÓÒÔÕÖÚÙÛÜÇÑ',
            'aaaaaeeeeiiiiooooouuuucnAAAAAEEEEIIIIOOOOOUUUUCN'),
          '[^a-zA-Z0-9]', '', 'g'
        )
      )
  ),
  matches AS (
    SELECT DISTINCT ON (person_idx)
      person_idx, membro_id
    FROM candidates
    WHERE rn = 1
    ORDER BY person_idx, created_at ASC NULLS LAST, membro_id
  )
  UPDATE _next_imp_persons p
  SET membro_id = matches.membro_id
  FROM matches
  WHERE matches.person_idx = p.person_idx;

  -- 4b) UUID deterministico (idempotencia robusta)
  --
  -- Para pessoas que nao casaram no passo 4 (sem telefone ou telefone que
  -- nao bate com nenhum mem_membros existente), deriva-se um UUID
  -- determinstico a partir de hash MD5 de (telefone_norm + nome). Isso
  -- garante que rodar a migration de novo encontre o mesmo membro_id ja
  -- criado, sem precisar de fallback por nome (que poderia mesclar
  -- pessoas diferentes com mesmo nome).
  UPDATE _next_imp_persons p
  SET membro_id = (
    substring(h, 1, 8) || '-' ||
    substring(h, 9, 4) || '-' ||
    '5' || substring(h, 14, 3) || '-' ||      -- forca versao 5
    'a' || substring(h, 18, 3) || '-' ||      -- forca variant 10xx
    substring(h, 21, 12)
  )::uuid
  FROM (
    SELECT
      person_idx,
      md5('next-import-historico-2025-2026:' ||
          coalesce(telefone_norm, '') || '|' ||
          lower(translate(coalesce(nome, ''),
            'áàâãäéèêëíìîïóòôõöúùûüçñÁÀÂÃÄÉÈÊËÍÌÎÏÓÒÔÕÖÚÙÛÜÇÑ',
            'aaaaaeeeeiiiiooooouuuucnAAAAAEEEEIIIIOOOOOUUUUCN'))
      ) AS h
    FROM _next_imp_persons
    WHERE membro_id IS NULL
  ) AS hashed
  WHERE p.person_idx = hashed.person_idx;

  -- 4c) Caso o UUID deterministico ja exista em mem_membros (rerun da
  -- migration ou colisao raro com import anterior), nao precisamos
  -- inserir — apenas linkar. O INSERT abaixo ja faz isso via
  -- WHERE NOT EXISTS.

  -- ------------------------------------------------------------------
  -- 5) Cria mem_membros para quem nao casou
  -- ------------------------------------------------------------------

  INSERT INTO mem_membros (
    id, nome, telefone, status, active, origem_cadastro, igreja_id, observacoes
  )
  SELECT
    p.membro_id,
    p.nome,
    p.telefone,
    'visitante',
    true,
    'import_next_historico_2025_2026',
    v_default_igreja_id,
    'Importado do backfill historico do NEXT (Jan/2025-Abr/2026). Telefone normalizado: ' || COALESCE(p.telefone_norm, '(sem telefone)')
  FROM _next_imp_persons p
  WHERE NOT EXISTS (SELECT 1 FROM mem_membros mm WHERE mm.id = p.membro_id);

  GET DIAGNOSTICS v_count_membros_novos = ROW_COUNT;
  RAISE NOTICE 'mem_membros novos criados: %', v_count_membros_novos;

  -- ------------------------------------------------------------------
  -- 6) Cria next_inscricoes (uma por evento x pessoa)
  --
  -- check_in_at = 10:00 do dia do evento, em America/Sao_Paulo, somente
  -- quando presente=true. Aproximacao do horario do culto.
  --
  -- origem='manual' (registro nao veio do formulario publico).
  -- origem_lista='impressa'|'manuscrito' (planilha original).
  -- ------------------------------------------------------------------
  INSERT INTO next_inscricoes (
    evento_id,
    nome,
    telefone,
    membro_id,
    origem,
    origem_lista,
    check_in_at,
    observacoes
  )
  SELECT
    e.id,
    p.nome,
    p.telefone,
    p.membro_id,
    'manual',
    r.fonte,
    CASE
      WHEN r.presente THEN (r.data + time '10:00') AT TIME ZONE 'America/Sao_Paulo'
      ELSE NULL
    END,
    r.observacao
  FROM _next_imp_records r
  JOIN next_eventos e ON e.data = r.data
  JOIN _next_imp_persons p ON p.person_idx = r.person_idx
  WHERE NOT EXISTS (
    SELECT 1 FROM next_inscricoes ni
    WHERE ni.evento_id = e.id AND ni.membro_id = p.membro_id
  );

  GET DIAGNOSTICS v_count_inscricoes = ROW_COUNT;
  RAISE NOTICE 'next_inscricoes criadas: %', v_count_inscricoes;

  RAISE NOTICE 'Backfill NEXT finalizado. eventos=%, membros_novos=%, inscricoes=%',
    v_count_eventos, v_count_membros_novos, v_count_inscricoes;
END
$migration$;
